using System.Drawing;
using System.Drawing.Design;
using System.Runtime.InteropServices;
using System.Runtime.InteropServices.Marshalling;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    private StatusStrip _statusStrip;

    protected override void OnLoad(EventArgs e)
    {
        base.OnLoad(e);

        // .NET 9 breaking change: the default ToolStrip render mode changed from
        // Professional to System, altering StatusStrip appearance. Restore the
        // .NET 8 look by setting the renderer explicitly.
        _statusStrip = new StatusStrip();
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }

    // .NET 9 breaking change: IWindowsFormsEditorService.DropDownControl now
    // throws ArgumentNullException when passed null. Guard against it.
    public void ShowEditor(IWindowsFormsEditorService editorService, Control editorControl)
    {
        ArgumentNullException.ThrowIfNull(editorService);

        if (editorControl is not null)
        {
            editorService.DropDownControl(editorControl);
        }
    }

    // .NET 9: prefer [LibraryImport] (source-generated) over [DllImport] for
    // better AOT compatibility and trimming support.
    [LibraryImport("user32.dll", EntryPoint = "MessageBoxW", StringMarshalling = StringMarshalling.Utf16)]
    private static partial int NativeMessageBox(nint hWnd, string text, string caption, uint type);

    public void ShowNativeMessage(string text, string caption)
    {
        NativeMessageBox(nint.Zero, text, caption, 0);
    }
}

